"use client";

import React, { createContext, useContext, useState, useEffect } from "react";
import { translations, Language } from "@/lib/translations";

interface LanguageContextType {
    language: Language;
    setLanguage: (lang: Language) => void;
    t: (path: string) => string;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export const LanguageProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [language, setLanguageState] = useState<Language>('hinglish');

    useEffect(() => {
        const savedLang = localStorage.getItem("language") as Language;
        if (savedLang && (savedLang === 'hinglish' || savedLang === 'english' || savedLang === 'hindi')) {
            setLanguageState(savedLang);
        }
    }, []);

    const setLanguage = (lang: Language) => {
        setLanguageState(lang);
        localStorage.setItem("language", lang);
    };

    const t = (path: string): string => {
        const keys = path.split('.');
        let current: unknown = translations[language];
        for (const key of keys) {
            if (current && typeof current === 'object' && key in (current as Record<string, unknown>)) {
                current = (current as Record<string, unknown>)[key];
            } else {
                console.warn(`Translation path not found: ${path} for language: ${language}`);
                return path;
            }
        }
        return typeof current === 'string' ? current : path;
    };

    return (
        <LanguageContext.Provider value={{ language, setLanguage, t }}>
            {children}
        </LanguageContext.Provider>
    );
};

export const useLanguage = () => {
    const context = useContext(LanguageContext);
    if (context === undefined) {
        throw new Error("useLanguage must be used within a LanguageProvider");
    }
    return context;
};

"use client";

import { useEffect } from "react";
import { useAuth } from "@/context/AuthContext";
import { db } from "@/lib/firebase";
import { doc, setDoc, serverTimestamp } from "firebase/firestore";

interface UserTrackingData {
    ip: string;
    userAgent: string;
    screenResolution: string;
    platform: string;
    language: string;
    lastActive: any; // ServerTimestamp
    email?: string;
    displayName?: string;
    photoURL?: string;
}

export const useUserTracking = () => {
    const { user } = useAuth();

    useEffect(() => {
        if (!user) return;

        const trackUser = async () => {
            try {
                // Fetch IP
                const ipResponse = await fetch("https://api.ipify.org?format=json");
                const ipData = await ipResponse.json();

                const trackingData: UserTrackingData = {
                    ip: ipData.ip,
                    userAgent: navigator.userAgent,
                    screenResolution: `${window.screen.width}x${window.screen.height}`,
                    platform: navigator.platform,
                    language: navigator.language,
                    lastActive: serverTimestamp(),
                    email: user.email || undefined,
                    displayName: user.displayName || undefined,
                    photoURL: user.photoURL || undefined,
                };

                // Update / users / {uid}
                // setDoc with merge: true to avoid overwriting existing non-tracking fields if any
                await setDoc(doc(db, "users", user.uid), trackingData, { merge: true });

                console.log("User tracked successfully:", user.email);

            } catch (error) {
                console.error("Error tracking user:", error);
            }
        };

        trackUser();
    }, [user]);
};

import { initializeApp, getApps, getApp } from "firebase/app";
import { getAuth } from "firebase/auth";
import { getFirestore } from "firebase/firestore";
import { getStorage } from "firebase/storage";

const firebaseConfig = {
    apiKey: process.env.NEXT_PUBLIC_FIREBASE_API_KEY,
    authDomain: process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN,
    projectId: process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID,
    storageBucket: process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET,
    messagingSenderId: process.env.NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID,
    appId: process.env.NEXT_PUBLIC_FIREBASE_APP_ID
};

// Initialize Firebase only if API key is present
let app;
let auth: any;
let db: any;
let storage: any;

if (firebaseConfig.apiKey) {
    app = getApps().length > 0 ? getApp() : initializeApp(firebaseConfig);
    auth = getAuth(app);
    db = getFirestore(app);
    storage = getStorage(app);
} else {
    console.warn("Firebase API Key is missing. Firebase features will not work.");
}

export { auth, db, storage };

